import json, pathlib, sys
from collections import defaultdict
sys.path.insert(0,'/app/task_file/scripts')
from cost_model import CostModel, HEADS, HIDDEN, align
root=pathlib.Path('/app/task_file')
cm=CostModel(64)

def eval_plan(reqs, mode, shape):
    groups=defaultdict(list)
    for r in reqs:
        s=align(r['prompt_len'],64)
        g=r['gen_len']
        if mode[0]=='gen_le' and g<=mode[1]:
            key=('g',g)
        elif mode[0]=='gen_eq' and g in mode[1]:
            key=('g',g)
        else:
            key=('sg',s,g)
        groups[key].append(r)
    plan=[]
    for i,(k,rs) in enumerate(sorted(groups.items(), key=lambda x:str(x[0])),1):
        bid=f'b-{i:04d}'
        for r in rs:
            plan.append({'request_id':r['request_id'],'batch_id':bid,'shape':{'seq_align':shape,'heads_align':HEADS,'hidden_align':HIDDEN}})
    reqmap={r['request_id']:r for r in reqs}
    return len(groups), cm.plan_metrics(reqmap, plan)

for req_name,shape in [('requests_bucket_1.jsonl',2048),('requests_bucket_2.jsonl',704)]:
    reqs=[json.loads(l) for l in (root/'input_data'/req_name).read_text().splitlines() if l.strip()]
    print('\n',req_name)
    for t in [16,20,24,32,40,48,56,64,80,96,128]:
        b,m=eval_plan(reqs,('gen_le',t),shape)
        print('<=',t,'batches',b,{k:round(m[k],3) for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']})
