        for s,rs in sorted(bys.items()):
            low=[r for r in rs if r['gen_len']<=t]
            high=[r for r in rs if r['gen_len']>t]
            if low:
                bid+=1; b=f'b-{bid:04d}'
                for r in low:
                    plan.append({'request_id':r['request_id'],'batch_id':b,'shape':{'seq_align':shapes[req_name],'heads_align':HEADS,'hidden_align':HIDDEN}})
            # exact groups for high by gen
            groups=defaultdict(list)
            for r in high: groups[r['gen_len']].append(r)
            for g,gr in sorted(groups.items()):
                bid+=1; b=f'b-{bid:04d}'
                for r in gr:
                    plan.append({'request_id':r['request_id'],'batch_id':b,'shape':{'seq_align':shapes[req_name],'heads_align':HEADS,'hidden_align':HIDDEN}})
        m=cm.plan_metrics({r['request_id']:r for r in reqs},plan)
        print('t',t,'batches',len({p['batch_id'] for p in plan}),{k:round(m[k],3) for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']})
